1	package fizeau
2	
3	import (
4		"context"
5		"errors"
6		"strings"
7		"time"
8	
9		"github.com/easel/fizeau/internal/provider/openai"
10		"github.com/easel/fizeau/internal/sdk/openaicompat"
11	)
12	
13	// QuotaRecoveryProber reports whether a quota_exhausted provider has recovered.
14	// A nil error indicates the provider is back online; a non-nil error keeps it
15	// in quota_exhausted with an extended retry_after.
16	type QuotaRecoveryProber func(ctx context.Context, provider string) error
17	
18	const (
19		// defaultQuotaRecoveryFallbackInterval is the wake interval used when no
20		// quota_exhausted provider has a known retry_after to drive the next probe.
21		defaultQuotaRecoveryFallbackInterval = 5 * time.Minute
22		// quotaRecoveryBackoffInitial is the first retry_after extension applied
23		// after a probe failure when no prior backoff is recorded.
24		quotaRecoveryBackoffInitial = 5 * time.Minute
25		// quotaRecoveryBackoffMax caps the exponential backoff between failed
26		// probes so a persistently-down provider is still re-probed at least
27		// once an hour.
28		quotaRecoveryBackoffMax = 1 * time.Hour
29	)
30	
31	// runQuotaRecoveryProbeLoop periodically probes providers that the store
32	// reports as quota_exhausted. When a provider's retry_after has elapsed (or
33	// is unknown) the loop calls probe; on success the provider is moved back to
34	// available, on failure its retry_after is extended with bounded exponential
35	// backoff. The loop exits when ctx is cancelled.
36	//
37	// fallback bounds the maximum sleep between passes. now/sleep are seams for
38	// deterministic tests; pass nil for production defaults.
39	func runQuotaRecoveryProbeLoop(
40		ctx context.Context,
41		store *ProviderQuotaStateStore,
42		probe QuotaRecoveryProber,
43		fallback time.Duration,
44		now func() time.Time,
45		sleep func(ctx context.Context, d time.Duration) bool,
46	) {
47		if ctx == nil || store == nil || probe == nil {
48			return
49		}
50		if fallback <= 0 {
51			fallback = defaultQuotaRecoveryFallbackInterval
52		}
53		if now == nil {
54			now = time.Now
55		}
56		if sleep == nil {
57			sleep = quotaRecoverySleep
58		}
59		backoffs := make(map[string]time.Duration)
60		for {
61			next := runQuotaRecoveryProbePass(ctx, store, probe, fallback, now, backoffs)
62			if !sleep(ctx, next) {
63				return
64			}
65		}
66	}
67	
68	// runQuotaRecoveryProbePass executes a single sweep over the quota_exhausted
69	// set and returns the duration to sleep before the next sweep.
70	func runQuotaRecoveryProbePass(
71		ctx context.Context,
72		store *ProviderQuotaStateStore,
73		probe QuotaRecoveryProber,
74		fallback time.Duration,
75		now func() time.Time,
76		backoffs map[string]time.Duration,
77	) time.Duration {
78		entries := store.AllExhausted()
79		t := now()
80		// Drop backoff bookkeeping for providers no longer exhausted (e.g.
81		// MarkAvailable was called externally) so a future re-exhaustion starts
82		// with a fresh initial backoff.
83		for name := range backoffs {
84			if _, ok := entries[name]; !ok {
85				delete(backoffs, name)
86			}
87		}
88		if len(entries) == 0 {
89			return fallback
90		}
91		nextWake := fallback
92		for name, retry := range entries {
93			if ctx.Err() != nil {
94				return fallback
95			}
96			if !retry.IsZero() && retry.After(t) {
97				if d := retry.Sub(t); d < nextWake {
98					nextWake = d
99				}
100				continue
101			}
102			if err := probe(ctx, name); err == nil {
103				store.MarkAvailable(name)
104				delete(backoffs, name)
105				continue
106			}
107			next := nextQuotaRecoveryBackoff(backoffs[name])
108			backoffs[name] = next
109			newRetry := t.Add(next)
110			store.MarkQuotaExhausted(name, newRetry)
111			if next < nextWake {
112				nextWake = next
113			}
114		}
115		if nextWake <= 0 {
116			nextWake = fallback
117		}
118		return nextWake
119	}
120	
121	// nextQuotaRecoveryBackoff returns the next bounded backoff value: doubles the
122	// previous extension, starting at quotaRecoveryBackoffInitial, capped at
123	// quotaRecoveryBackoffMax.
124	func nextQuotaRecoveryBackoff(prev time.Duration) time.Duration {
125		if prev <= 0 {
126			return quotaRecoveryBackoffInitial
127		}
128		next := prev * 2
129		if next > quotaRecoveryBackoffMax {
130			return quotaRecoveryBackoffMax
131		}
132		return next
133	}
134	
135	// quotaRecoverySleep blocks for d or until ctx is cancelled. Returns true if
136	// the sleep completed normally and false if ctx was cancelled.
137	func quotaRecoverySleep(ctx context.Context, d time.Duration) bool {
138		if d <= 0 {
139			return ctx.Err() == nil
140		}
141		timer := time.NewTimer(d)
142		defer timer.Stop()
143		select {
144		case <-ctx.Done():
145			return false
146		case <-timer.C:
147			return true
148		}
149	}
150	
151	// probeOpenAIModels calls GET /v1/models against baseURL and classifies
152	// failures into the three shapes the catalog cache understands:
153	//
154	//   - *openai.ReachabilityError for 5xx / transport failures (endpoint
155	//     unreachable); cache sets an UnreachableCooldown.
156	//   - errDiscoveryUnsupported for 404 / endpoints that don't expose
157	//     /v1/models; cache marks DiscoverySupported=false and callers
158	//     fall back to passthrough model naming.
159	//   - other errors (401/403 auth, unexpected body) are returned as-is;
160	//     the cache records them but doesn't mark the endpoint unreachable.
161	//
162	// The returned IDs are whatever the server returned in its `data[].id`
163	// list, preserving server-provided order.
164	func probeOpenAIModels(ctx context.Context, baseURL, apiKey string) ([]string, error) {
165		ids, err := openaicompat.DiscoverModels(ctx, baseURL, apiKey)
166		if err == nil {
167			return ids, nil
168		}
169		msg := err.Error()
170		// openaicompat.DiscoverModels returns errors prefixed with
171		// "HTTP <code>: <body>" for non-2xx responses.
172		if strings.Contains(msg, "HTTP 404") {
173			return nil, ErrDiscoveryUnsupported()
174		}
175		if isServerError(msg) || isNetworkFailure(err) {
176			return nil, &openai.ReachabilityError{
177				Endpoint:   baseURL,
178				Operation:  "probe_models",
179				StatusCode: extractStatusCode(msg),
180				Cause:      err,
181			}
182		}
183		return nil, err
184	}
185	
186	// isServerError returns true when the error message indicates a 5xx
187	// response from the discovery endpoint.
188	func isServerError(msg string) bool {
189		for _, prefix := range []string{"HTTP 500", "HTTP 501", "HTTP 502", "HTTP 503", "HTTP 504", "HTTP 505"} {
190			if strings.Contains(msg, prefix) {
191				return true
192			}
193		}
194		return false
195	}
196	
197	// isNetworkFailure returns true when err looks like a transport-level
198	// failure (dial, timeout, TLS, connection reset) — the ReachabilityError
199	// classification applies.
200	func isNetworkFailure(err error) bool {
201		if err == nil {
202			return false
203		}
204		msg := err.Error()
205		markers := []string{
206			"connection refused",
207			"connection reset",
208			"no such host",
209			"tls: handshake",
210			"TLS handshake",
211			"i/o timeout",
212			"dial tcp",
213			"broken pipe",
214		}
215		for _, m := range markers {
216			if strings.Contains(msg, m) {
217				return true
218			}
219		}
220		// Explicitly NOT classifying context.DeadlineExceeded as network —
221		// that's the caller's own deadline.
222		return errors.Is(err, errDialishNetworkError)
223	}
224	
225	// extractStatusCode pulls the status code out of the "HTTP NNN:" prefix
226	// used by openaicompat.DiscoverModels. Returns 0 when no code is found.
227	func extractStatusCode(msg string) int {
228		const prefix = "HTTP "
229		idx := strings.Index(msg, prefix)
230		if idx < 0 {
231			return 0
232		}
233		tail := msg[idx+len(prefix):]
234		if len(tail) < 3 {
235			return 0
236		}
237		code := 0
238		for i := 0; i < 3 && i < len(tail); i++ {
239			c := tail[i]
240			if c < '0' || c > '9' {
241				return 0
242			}
243			code = code*10 + int(c-'0')
244		}
245		return code
246	}
247	
248	// errDialishNetworkError is a sentinel for errors.Is tests. Callers may
249	// wrap their own network errors with this to ensure isNetworkFailure
250	// picks them up even when the message doesn't match one of the literal
251	// markers.
252	var errDialishNetworkError = errors.New("agent: network failure")
253

