12	type executeRouteResolver interface {
13		resolveExecuteRoute(ServiceExecuteRequest) (*RouteDecision, error)
14		resolveExecuteRouteContext(context.Context, ServiceExecuteRequest) (*RouteDecision, error)
15	}
16	
17	type executeSessionLogOpener interface {
18		openSessionLog(ServiceExecuteRequest, RouteDecision, string) *serviceSessionLog
19	}
20	
21	type executeEventFanout interface {
22		OpenSession(string)
23		BroadcastEvent(string, ServiceEvent)
24		CloseSession(string, ServiceEvent)
25	}
26	
27	type executeRunnerInvoker interface {
28		dispatchExecuteRun(context.Context, executeRunContext)
29	}
30	
31	type executeRunContext struct {
32		req      ServiceExecuteRequest
33		decision RouteDecision
34		meta     map[string]string
35		out      chan<- ServiceEvent
36		seq      *atomic.Int64
37		start    time.Time
38		sl       *serviceSessionLog
39		session  string
40	}
41	
42	func (s *service) executeRouteResolver() executeRouteResolver {
43		return s
44	}
45	
46	func (s *service) executeSessionLogOpener() executeSessionLogOpener {
47		return s
48	}
49	
50	func (s *service) executeEventFanout() executeEventFanout {
51		return s.hub
52	}
53	
54	func (s *service) executeRunnerInvoker() executeRunnerInvoker {
55		return s
56	}
