58	func (s *service) dispatchExecuteRun(ctx context.Context, run executeRunContext) {
59		decision := serviceimpl.ExecuteRunnerDecision{
60			Harness:  run.decision.Harness,
61			Provider: run.decision.Provider,
62			Model:    run.decision.Model,
63		}
64		serviceimpl.DispatchExecuteRun(ctx, serviceimpl.ExecuteDispatchRequest{
65			Decision: decision,
66			Started:  run.start,
67		}, serviceimpl.ExecuteDispatchCallbacks{
68			RunNative: func(ctx context.Context) {
69				s.runNative(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
70			},
71			RunSubprocess: func(ctx context.Context, runner harnesses.Harness) {
72				s.runSubprocess(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session, runner)
73			},
74			RunVirtual: func(ctx context.Context) {
75				s.runVirtual(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
76			},
77			RunScript: func(ctx context.Context) {
78				s.runScript(ctx, run.req, run.decision, run.meta, run.out, run.seq, run.start, run.sl, run.session)
79			},
80			IsHTTPProvider: func(harness string) bool {
81				cfg, ok := s.registry.Get(harness)
82				return ok && cfg.IsHTTPProvider
83			},
84			Finalize: func(final harnesses.FinalData) {
85				s.recordRouteAttemptFromFinal(final)
86				finalizeAndEmit(run.out, run.seq, run.meta, run.req, run.sl, final)
87			},
88		})
89	}
