274	func validateExplicitHarnessPolicy(name string, cfg harnesses.HarnessConfig, policy string) error {
275		constraint, ok := explicitPolicyConstraint(policy)
276		if !ok {
277			return nil
278		}
279		switch constraint {
280		case routing.ProviderPreferenceLocalOnly:
281			if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelFixed {
282				return &ErrPolicyRequirementUnsatisfied{
283					Policy:       policy,
284					Requirement:  constraint,
285					AttemptedPin: "Harness=" + name,
286				}
287			}
288		case routing.ProviderPreferenceSubscriptionOnly:
289			if harnessPaymentKind(name, cfg) != modelcatalog.BillingModelSubscription {
290				return &ErrPolicyRequirementUnsatisfied{
291					Policy:       policy,
292					Requirement:  constraint,
293					AttemptedPin: "Harness=" + name,
294				}
295			}
296		}
297		return nil
298	}
