311	func isExplicitPinError(err error) bool {
312		var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
313		if errors.As(err, &modelConstraintAmbiguous) {
314			return true
315		}
316		var modelConstraintNoMatch *ErrModelConstraintNoMatch
317		if errors.As(err, &modelConstraintNoMatch) {
318			return true
319		}
320		var modelErr *ErrHarnessModelIncompatible
321		if errors.As(err, &modelErr) {
322			return true
323		}
324		var policyErr *ErrPolicyRequirementUnsatisfied
325		if errors.As(err, &policyErr) && policyErr.AttemptedPin != "" {
326			return true
327		}
328		var pinErr *ErrUnsatisfiablePin
329		if errors.As(err, &pinErr) {
330			return true
331		}
332		var providerErr *ErrUnknownProvider
333		return errors.As(err, &providerErr)
