336	// validateExplicitProvider rejects pre-dispatch when the caller pinned a
337	// provider name that the service configuration does not recognize. Returns
338	// nil when no provider was pinned, when no ServiceConfig is configured (no
339	// provider catalog to validate against), when the provider name is known,
340	// or when the harness is test-only / does not consume Provider (virtual,
341	// script, etc. have no real provider lookup).
342	func validateExplicitProvider(sc ServiceConfig, cfg harnesses.HarnessConfig, provider string) error {
343		if provider == "" || sc == nil {
344			return nil
345		}
346		if cfg.TestOnly {
347			return nil
348		}
349		lookup := provider
350		if base, _, ok := splitEndpointProviderRef(provider); ok {
351			lookup = base
352		}
353		if _, ok := sc.Provider(lookup); ok {
354			return nil
355		}
356		known := sc.ProviderNames()
357		return &ErrUnknownProvider{Provider: provider, KnownProviders: append([]string(nil), known...)}
358	}
