360	func validateExplicitHarnessModel(name string, cfg harnesses.HarnessConfig, model, provider string) error {
361		if model == "" || cfg.TestOnly || cfg.IsHTTPProvider || name == "fiz" {
362			return nil
363		}
364		if modelSupportedForHarness(name, cfg, model, provider) {
365			return nil
366		}
367		supportedModels := subprocessHarnessModelIDs(name, cfg)
368		return &ErrHarnessModelIncompatible{
369			Harness:         name,
370			Model:           model,
371			SupportedModels: append([]string(nil), supportedModels...),
372		}
373	}
374	
375	func modelSupportedForHarness(name string, cfg harnesses.HarnessConfig, model, provider string) bool {
376		for _, known := range subprocessHarnessModelIDs(name, cfg) {
377			if model == known {
378				return true
379			}
380		}
381		switch name {
382		case "codex":
383			return strings.HasPrefix(model, "gpt-")
384		case "claude":
385			return strings.HasPrefix(model, "claude-")
386		case "pi":
387			// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
388			// provider is pinned. The pi CLI owns per-provider model validation
389			// in that case, so the agent-side gate trusts the provider pin and
390			// defers concrete model-ID checks to pi --list-models / pi itself.
391			return provider != ""
392		case "opencode":
393			// OpenCode can route to configured provider/model pairs when the
394			// provider is pinned; the generated opencode config and CLI own the
395			// concrete model validation in that case.
396			return provider != ""
397		default:
398			return len(cfg.Models) == 0
399		}
400	}
