402	func (s *service) validateEngineResolvedExecuteDecision(req ServiceExecuteRequest, decision *RouteDecision) error {
403		if decision == nil || strings.TrimSpace(req.Harness) == "" || strings.TrimSpace(req.Model) != "" {
404			return nil
405		}
406		canonical := harnesses.ResolveHarnessAlias(req.Harness)
407		if decision.Harness != "" && decision.Harness != canonical {
408			return &ErrUnsatisfiablePin{
409				Pin:    "harness=" + canonical,
410				Reason: "routing engine returned a different harness",
411			}
412		}
413		cfg, ok := s.registry.Get(canonical)
414		if !ok {
415			return fmt.Errorf("unknown harness %q", req.Harness)
416		}
417		normalizedModel := resolveSubprocessModelAlias(canonical, decision.Model)
418		if err := validateExplicitHarnessModel(canonical, cfg, normalizedModel, decision.Provider); err != nil {
419			return err
420		}
421		decision.Harness = canonical
422		decision.Model = normalizedModel
423		if decision.Endpoint == "" {
424			_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
425			decision.Endpoint = endpoint
426		}
427		return nil
428	}
