430	func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
431		if cfg.TestOnly {
432			return nil
433		}
434		if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
435			return nil
436		}
437		policy, err := reasoning.ParseString(string(value))
438		if err != nil {
439			return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
440		}
441		switch policy.Kind {
442		case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
443			return nil
444		case reasoning.KindTokens:
445			if cfg.MaxReasoningTokens <= 0 {
446				return fmt.Errorf("unsupported reasoning %q for harness %q; token budgets are not supported", value, name)
447			}
448			if policy.Tokens > cfg.MaxReasoningTokens {
449				return fmt.Errorf("unsupported reasoning %q for harness %q; max token budget is %d", value, name, cfg.MaxReasoningTokens)
450			}
451			return nil
452		case reasoning.KindNamed:
453			for _, supported := range cfg.ReasoningLevels {
454				if string(policy.Value) == supported {
455					return nil
456				}
457			}
458			return fmt.Errorf("unsupported reasoning %q for harness %q; supported reasoning: %s", value, name, strings.Join(cfg.ReasoningLevels, ", "))
459		default:
460			return fmt.Errorf("unsupported reasoning %q for harness %q", value, name)
461		}
462	}
