471	// runExecute is the per-Execute goroutine. It owns the channel close path
472	// and the final event emit. All termination paths funnel through emitFinal
473	// so the channel always sees a final event before close.
474	func (s *service) runExecute(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, sessionID string, overrideCtx *overrideContext) {
475		defer close(out)
476	
477		start := time.Now()
478		var seq atomic.Int64
479	
480		// Open the service-owned session log writer and guarantee a terminal
481		// session.end record plus a clean file close even on unexpected exits.
482		// CONTRACT-003 makes session-log lifecycle a service responsibility; the
483		// per-path finalizeAndEmit calls below feed writeEnd in lock-step with
484		// the public final event.
485		sl := s.executeSessionLogOpener().openSessionLog(req, decision, sessionID)
486		if overrideCtx != nil {
487			sl.override = overrideCtx
488		}
489		defer func() {
490			if !sl.endWritten() {
491				sl.writeEnd(req, meta, harnesses.FinalData{
492					Status:     "cancelled",
493					Error:      "session ended without final event",
494					DurationMS: time.Since(start).Milliseconds(),
495					RoutingActual: &harnesses.RoutingActual{
496						Harness:  decision.Harness,
497						Provider: decision.Provider,
498						Model:    decision.Model,
499					},
500				})
501			}
502			sl.close()
503		}()
504	
505		// Wall-clock cap.
506		runCtx := ctx
507		if req.Timeout > 0 {
508			var cancel context.CancelFunc
509			runCtx, cancel = context.WithTimeout(ctx, req.Timeout)
510			defer cancel()
511		}
512	
513		// Emit routing_decision start event. Include session_id so callers can
514		// extract it and pass to TailSessionLog. Per CONTRACT-003 the
515		// top-level Role + CorrelationID are echoed into routing_decision
516		// event Metadata (top-level wins over caller Metadata for these
517		// reserved keys).
518		routingMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
519		emitJSON(out, &seq, harnesses.EventTypeRoutingDecision, routingMeta, serviceRoutingDecisionDataFromDecision(req, decision, sessionID))
520		emitProgress(out, &seq, sl, sessionID, meta, routeProgressData(decision))
521	
522		s.executeRunnerInvoker().dispatchExecuteRun(runCtx, executeRunContext{
523			req:      req,
524			decision: decision,
525			meta:     meta,
526			out:      out,
527			seq:      &seq,
528			start:    start,
529			sl:       sl,
530			session:  sessionID,
531		})
532	}
