534	func (s *service) runVirtual(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
535		progress := newSubprocessProgressState(req)
536		emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
537		result := serviceimpl.RunVirtual(ctx, executeRunnerRequest(req, decision, meta, start))
538		final := result.Final
539		if result.EmitText {
540			emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
541		}
542		if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
543			emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
544		}
545		s.recordRouteAttemptFromFinal(final)
546		finalizeAndEmit(out, seq, meta, req, sl, final)
547	}
