585	// runNative drives the in-process agent loop (loop.go's Run). The provider
586	// is wrapped so per-HTTP timeouts fire independently of the request wall-clock
587	// cap.
588	func (s *service) runNative(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
589		progress := newNativeProgressState()
590		observeAgentEvent := func(ev agentcore.Event) {
591			sl.writeEvent(ev)
592			switch ev.Type {
593			case agentcore.EventLLMRequest:
594				var payload nativeLLMRequestPayload
595				if err := json.Unmarshal(ev.Data, &payload); err == nil {
596					emitProgress(out, seq, sl, sessionID, meta, progress.noteRequest(payload))
597				}
598			case agentcore.EventLLMResponse:
599				var payload nativeLLMResponsePayload
600				if err := json.Unmarshal(ev.Data, &payload); err == nil {
601					emitProgress(out, seq, sl, sessionID, meta, progress.noteResponse(payload))
602				}
603			case agentcore.EventToolCall:
604				var payload nativeToolCallPayload
605				_ = json.Unmarshal(ev.Data, &payload)
606				toolName := payload.Tool
607				input := payload.Input
608				if input == nil {
609					if rawIn, err := json.Marshal(map[string]any{"tool": toolName}); err == nil {
610						input = rawIn
611					}
612				}
613				callID := fmt.Sprintf("call-%d", ev.Seq)
614				_, completeProgress := progress.noteToolCall(callID, payload)
615				emitJSONRaw(out, seq, harnesses.EventTypeToolCall, meta, harnesses.ToolCallData{
616					ID:    callID,
617					Name:  toolName,
618					Input: input,
619				})
620				emitJSONRaw(out, seq, harnesses.EventTypeToolResult, meta, harnesses.ToolResultData{
621					ID:         callID,
622					Output:     payload.Output,
623					Error:      payload.Error,
624					DurationMS: payload.DurationMS,
625				})
626				emitProgress(out, seq, sl, sessionID, meta, completeProgress)
627			case agentcore.EventCompactionEnd:
628				var payload nativeCompactionPayload
629				_ = json.Unmarshal(ev.Data, &payload)
630				emitJSONRaw(out, seq, harnesses.EventTypeCompaction, meta, map[string]any{
631					"messages_before": payload.MessagesBefore,
632					"messages_after":  payload.MessagesAfter,
633					"tokens_freed":    payload.TokensBefore - payload.TokensAfter,
634				})
635				compactionProgress, contextProgress := progress.noteCompaction(payload)
636				emitProgress(out, seq, sl, sessionID, meta, compactionProgress)
637				emitProgress(out, seq, sl, sessionID, meta, contextProgress)
638			}
639		}
640	
641		var stallMaxReadOnlyIterations *int
642		if req.StallPolicy != nil {
643			stallMaxReadOnlyIterations = &req.StallPolicy.MaxReadOnlyToolIterations
644		}
645		serviceimpl.RunNative(ctx, serviceimpl.NativeRequest{
646			Prompt:                    req.Prompt,
647			SystemPrompt:              req.SystemPrompt,
648			Model:                     req.Model,
649			Provider:                  req.Provider,
650			Harness:                   req.Harness,
651			WorkDir:                   req.WorkDir,
652			Temperature:               req.Temperature,
653			TopP:                      req.TopP,
654			TopK:                      req.TopK,
655			MinP:                      req.MinP,
656			RepetitionPenalty:         req.RepetitionPenalty,
657			Seed:                      req.Seed,
658			SamplingSource:            req.SamplingSource,
659			Reasoning:                 effectiveReasoning(req.Reasoning),
660			NoStream:                  req.NoStream,
661			Permissions:               req.Permissions,
662			Tools:                     nativeToolsForRequest(req),
663			ToolPreset:                req.ToolPreset,
664			PlanningMode:              req.PlanningMode,
665			MaxIterations:             req.MaxIterations,
666			MaxTokens:                 req.MaxTokens,
667			ReasoningByteLimit:        req.ReasoningByteLimit,
668			ProviderTimeout:           req.ProviderTimeout,
669			Timeout:                   req.Timeout,
670			CachePolicy:               req.CachePolicy,
671			CostCapUSD:                req.CostCapUSD,
672			StallMaxReadOnlyIteration: stallMaxReadOnlyIterations,
673			Metadata:                  meta,
674			Decision:                  nativeDecision(decision),
675			Started:                   start,
676			SessionID:                 sessionID,
677		}, serviceimpl.NativeCallbacks{
678			ResolveProvider: func(nreq serviceimpl.NativeProviderRequest) serviceimpl.NativeProviderResolution {
679				resolved := s.resolveNativeProvider(ServiceExecuteRequest{
680					Provider: nreq.Provider,
681					Harness:  nreq.Harness,
682					Model:    nreq.Model,
683				})
684				return serviceimpl.NativeProviderResolution{
685					Provider: resolved.Provider,
686					Name:     resolved.Name,
687					Model:    resolved.Entry.Model,
688				}
689			},
690			ProviderNotConfiguredError: func(nreq serviceimpl.NativeProviderRequest, ndecision serviceimpl.NativeDecision) string {
691				return s.nativeProviderNotConfiguredError(ServiceExecuteRequest{
692					Provider: nreq.Provider,
693					Harness:  nreq.Harness,
694					Model:    nreq.Model,
695				}, routeDecision(ndecision))
696			},
697			Compactor: func(model string) agentcore.Compactor {
698				return newServiceCompactor(req, model)
699			},
700			ObserveAgentEvent: observeAgentEvent,
701			EmitEvent: func(t harnesses.EventType, payload any) {
702				emitJSONRaw(out, seq, t, meta, payload)
703			},
704			BeforeFinal: func(final harnesses.FinalData) {
705				if progressFinal := progress.noteFinal(final); progressFinal != nil {
706					emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
707				}
708			},
709			Finalize: func(final harnesses.FinalData) {
710				s.recordRouteAttemptFromFinal(final)
711				finalizeAndEmit(out, seq, meta, req, sl, final)
712			},
713			ToolWiringHook:          s.toolWiringHook(),
714			PromptAssertionHook:     s.promptAssertionHook(),
715			CompactionAssertionHook: s.compactionAssertionHook(),
716			ObserveTokenUsage:       s.observeTokenUsage,
717		})
718	}
