756	func newServiceCompactor(req ServiceExecuteRequest, model string) agentcore.Compactor {
757		cfg := compaction.DefaultConfig()
758		if req.CompactionContextWindow > 0 {
759			cfg.ContextWindow = req.CompactionContextWindow
760			if cfg.ReserveTokens >= cfg.ContextWindow {
761				cfg.ReserveTokens = 0
762			}
763			if cfg.KeepRecentTokens > cfg.ContextWindow {
764				cfg.KeepRecentTokens = cfg.ContextWindow / 2
765			}
766		}
767		if req.CompactionReserveTokens > 0 {
768			cfg.ReserveTokens = req.CompactionReserveTokens
769		}
770		if catalog, err := modelcatalog.Default(); err == nil && catalog != nil && model != "" && req.CompactionContextWindow <= 0 {
771			if contextWindow := catalog.ContextWindowForModel(model); contextWindow > 0 {
772				cfg.ContextWindow = contextWindow
773			}
774		}
775		return compaction.NewCompactor(cfg)
776	}
