781	func (s *service) runSubprocess(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string, runner harnesses.Harness) {
782		progress := newSubprocessProgressState(req)
783		serviceimpl.RunSubprocess(ctx, serviceimpl.SubprocessRequest{
784			Prompt:        req.Prompt,
785			SystemPrompt:  req.SystemPrompt,
786			WorkDir:       req.WorkDir,
787			Permissions:   req.Permissions,
788			Temperature:   req.Temperature,
789			Seed:          req.Seed,
790			Reasoning:     effectiveReasoning(req.Reasoning),
791			Timeout:       req.Timeout,
792			IdleTimeout:   req.IdleTimeout,
793			SessionLogDir: req.SessionLogDir,
794			Metadata:      meta,
795			Decision: serviceimpl.ExecuteRunnerDecision{
796				Harness:  decision.Harness,
797				Provider: decision.Provider,
798				Model:    decision.Model,
799			},
800			Started:        start,
801			SessionLogPath: sessionLogPath(sl),
802		}, runner, serviceimpl.SubprocessCallbacks{
803			BeforeExecute: func() {
804				emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
805			},
806			BeforeFinal: func(final harnesses.FinalData) {
807			},
808			ObserveEvent: func(ev harnesses.Event) harnesses.Event {
809				ev = progress.annotateToolResultDuration(ev)
810				if payload, ok := progress.noteEvent(ev); ok && ev.Type != harnesses.EventTypeProgress {
811					emitProgress(out, seq, sl, sessionID, meta, payload)
812				}
813				if ev.Type == harnesses.EventTypeFinal {
814					if payload, ok := progress.noteFinal(ev); ok {
815						emitProgress(out, seq, sl, sessionID, meta, payload)
816					}
817				}
818				return ev
819			},
820			EmitEvent: func(ev harnesses.Event) bool {
821				ev.Sequence = seq.Add(1) - 1
822				select {
823				case out <- ev:
824					return true
825				case <-ctx.Done():
826					return false
827				}
828			},
829			Finalize: func(final harnesses.FinalData) {
830				s.recordRouteAttemptFromFinal(final)
831				finalizeAndEmit(out, seq, meta, req, sl, final)
832			},
833			WriteEnd: func(finalMeta map[string]string, final harnesses.FinalData) {
834				sl.writeEnd(req, finalMeta, final)
835			},
836		})
837	}
