846	// emitFinal wraps a FinalData into a ServiceEvent and writes it to out.
847	// The channel close happens in the caller via defer; this only writes the
848	// terminator event.
849	func emitFinal(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, final harnesses.FinalData) {
850		raw, err := json.Marshal(final)
851		if err != nil {
