912	// finalizeAndEmit stamps the service-owned session-log path onto final,
913	// records the terminal session.end event, and forwards the final to the
914	// public event stream. Every terminal emit path in runExecute funnels
915	// through this helper so the session log and the event channel stay in
916	// lock-step (CONTRACT-003).
917	//
918	// finalizeAndEmit also performs the CONTRACT-003 echo of top-level Role
919	// and CorrelationID into the final event Metadata (top-level wins over
920	// any caller-supplied Metadata entry under the same reserved key) and
921	// stamps RoutingActual.Power from the catalog projection of the
922	// actually-dispatched Model. When the caller set both top-level
923	// Role/CorrelationID and the same reserved Metadata key, a
924	// MetadataKeyCollision warning is appended to final.Warnings.
925	func finalizeAndEmit(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, req ServiceExecuteRequest, sl *serviceSessionLog, final harnesses.FinalData) {
926		if sl != nil && sl.path != "" {
927			final.SessionLogPath = sl.path
928		}
929		// Stamp catalog power onto the actually-dispatched RoutingActual.
930		// final.RoutingActual is set by the caller (one per terminal path);
931		// when nil we leave it nil to avoid synthesizing routing evidence.
932		if final.RoutingActual != nil && final.RoutingActual.Power == 0 {
933			final.RoutingActual.Power = catalogPowerForModel(serviceRoutingCatalog(), final.RoutingActual.Model)
934		}
935		// Detect reserved metadata-key collisions and append a warning so the
936		// caller learns when their caller-supplied Metadata entries were
937		// overridden by the top-level Role / CorrelationID fields.
938		if collisions := metadataReservedKeyCollisions(req.Metadata, req.Role, req.CorrelationID); len(collisions) > 0 {
939			final.Warnings = append(final.Warnings, harnesses.FinalWarning{
940				Code:    MetadataWarningCodeKeyCollision,
941				Message: metadataKeyCollisionMessage(collisions),
942			})
943		}
944		// Echo Role + CorrelationID onto the final event Metadata.
945		finalMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
946		if sl != nil {
947			if ovr := sl.override; ovr != nil && !ovr.emitted.Load() {
948				sl.writeOverrideEvent(ServiceEventTypeOverride, ovr.payload)
949			}
950			sl.writeEnd(req, finalMeta, final)
951		}
952		emitFinal(out, seq, finalMeta, final)
953	}
