41	func routeAttemptFromFinal(final harnesses.FinalData) (RouteAttempt, bool) {
42		if final.RoutingActual == nil {
43			return RouteAttempt{}, false
44		}
45		attempt := RouteAttempt{
46			Harness:  strings.TrimSpace(final.RoutingActual.Harness),
47			Provider: strings.TrimSpace(final.RoutingActual.Provider),
48			Model:    strings.TrimSpace(final.RoutingActual.Model),
49			Status:   strings.TrimSpace(final.Status),
50			Reason:   routeAttemptFailureClass(final),
51			Error:    strings.TrimSpace(final.Error),
52		}
53		if attempt.Status == "" || (attempt.Harness == "" && attempt.Provider == "") {
54			return RouteAttempt{}, false
55		}
56		if final.DurationMS > 0 {
57			attempt.Duration = time.Duration(final.DurationMS) * time.Millisecond
58		}
59		if providerName, endpointName, ok := splitEndpointProviderRef(attempt.Provider); ok {
60			attempt.Provider = providerName
61			attempt.Endpoint = endpointName
62		}
63		if routehealth.Succeeded(strings.ToLower(attempt.Status)) {
64			return attempt, true
65		}
66		if !isRouteAttemptDispatchFailure(attempt.Reason) {
67			return RouteAttempt{}, false
68		}
69		return attempt, true
70	}
