72	func routeAttemptFailureClass(final harnesses.FinalData) string {
73		if final.RoutingActual == nil {
74			return ""
75		}
76		if cls := strings.ToLower(strings.TrimSpace(final.RoutingActual.FailureClass)); cls != "" {
77			return cls
78		}
79		return classifyRouteAttemptFailure(final.Error)
80	}
