82	func isRouteAttemptDispatchFailure(class string) bool {
83		switch strings.ToLower(strings.TrimSpace(class)) {
84		case "availability", "protocol", "transport":
85			return true
86		default:
87			return false
88		}
89	}
90	
91	func classifyRouteAttemptFailure(errMsg string) string {
92		msg := strings.ToLower(strings.TrimSpace(errMsg))
93		switch {
94		case msg == "":
95			return ""
96		case strings.Contains(msg, "no provider configured"),
97			strings.Contains(msg, "not available"),
98			strings.Contains(msg, "exhausted"),
99			strings.Contains(msg, "not configured"),
100			strings.Contains(msg, "binary not found"):
101			return "availability"
102		case strings.Contains(msg, "timeout"),
103			strings.Contains(msg, "deadline"),
104			strings.Contains(msg, "connection"),
105			strings.Contains(msg, "refused"),
106			strings.Contains(msg, "no such host"),
107			strings.Contains(msg, "transport"),
108			strings.Contains(msg, "dial tcp"),
109			strings.Contains(msg, "network is unreachable"),
110			strings.Contains(msg, "no route to host"),
111			strings.Contains(msg, "i/o timeout"):
112			return "transport"
113		case strings.Contains(msg, "http "),
114			strings.Contains(msg, "status "),
115			strings.Contains(msg, "bad request"),
116			strings.Contains(msg, "unauthorized"),
117			strings.Contains(msg, "not found"),
118			strings.Contains(msg, "unsupported"):
119			return "protocol"
120		default:
121			return ""
122		}
123	}
