28	// ProviderAlivenessProber reports whether a provider endpoint is reachable.
29	// Returns true if reachable, false if not. The prober must respect ctx for
30	// cancellation.
31	type ProviderAlivenessProber func(ctx context.Context, provider, baseURL string) bool
