143	// requestLocalHealthRefreshForRouting starts at most one asynchronous refresh
144	// for stale or missing local provider aliveness evidence. Route hot paths use
145	// cached probe evidence only; this method must not wait for provider IO.
146	func (s *service) requestLocalHealthRefreshForRouting(_ context.Context) {
147		if s == nil || s.providerProbe == nil {
148			return
149		}
150		endpoints := s.routeTimeAlivenessEndpoints(time.Now().UTC())
151		if len(endpoints) == 0 {
152			return
153		}
154		if !s.providerProbeRefreshInFlight.CompareAndSwap(false, true) {
155			return
156		}
157		prober := s.opts.AlivenessProber
158		if prober == nil {
159			prober = tcpAlivenessProber
160		}
161		refreshCtx := context.Background()
162		go func() {
163			defer s.providerProbeRefreshInFlight.Store(false)
164			runRouteTimeAlivenessProbes(refreshCtx, endpoints, s.providerProbe, prober, routeTimeProbeTimeout)
165			s.persistProbeStore()
166		}()
167	}
