170		if s == nil || s.providerProbe == nil {
171			return nil
172		}
173		endpoints := s.alivenessEndpoints()
174		if len(endpoints) == 0 {
175			return nil
176		}
177		if now.IsZero() {
178			now = time.Now().UTC()
179		}
180		ttl := s.healthSignalTTL()
181		out := make(map[string]time.Time)
182		for _, ep := range endpoints {
183			record, ok := s.lastProbeForAlivenessEndpoint(ep)
184			if !ok {
185				for _, key := range alivenessRouteKeys(ep) {
186					out[key] = time.Time{}
187				}
188				continue
189			}
190			if ttl > 0 && now.Sub(record.LastProbeAt) > ttl {
191				for _, key := range alivenessRouteKeys(ep) {
192					out[key] = record.LastProbeAt
193				}
194			}
195		}
196		if len(out) == 0 {
197			return nil
198		}
199		return out
200	}
