245			now = time.Now().UTC()
246		}
247		ttl := s.healthSignalTTL()
248		out := make(map[string]time.Time)
249		for _, ep := range endpoints {
250			record, ok := s.lastProbeForAlivenessEndpoint(ep)
251			if !ok || record.LastProbeSuccess {
