272		}
273		if r, ok := s.providerProbe.LastProbe(ep.provider, ep.endpoint); ok {
274			return r, true
275		}
276		if ep.endpoint != "" {
277			return s.providerProbe.LastProbe(ep.provider, "")
278		}
279		return routehealth.ProbeRecord{}, false
