298	func runRouteTimeAlivenessProbes(
299		ctx context.Context,
300		endpoints []alivenessEndpoint,
301		store *routehealth.ProbeStore,
302		prober ProviderAlivenessProber,
303		perProbeTimeout time.Duration,
304	) {
305		if len(endpoints) == 0 || store == nil || prober == nil {
306			return
307		}
308		if ctx == nil {
309			ctx = context.Background()
310		}
311		if perProbeTimeout <= 0 {
312			perProbeTimeout = routeTimeProbeTimeout
313		}
314		for i, ep := range endpoints {
315			if ctx.Err() != nil {
316				recordRouteTimeProbeFailures(store, endpoints[i:], time.Now().UTC())
317				return
318			}
319			probeAt := time.Now().UTC()
320			probeCtx, cancel := context.WithTimeout(ctx, perProbeTimeout)
321			success := prober(probeCtx, ep.provider, ep.baseURL)
322			if probeCtx.Err() != nil {
323				success = false
324			}
325			cancel()
326			store.RecordProbe(ep.provider, ep.endpoint, success, probeAt)
327			if ctx.Err() != nil {
328				recordRouteTimeProbeFailures(store, endpoints[i+1:], probeAt)
329				return
330			}
331		}
332	}
