343	// startAlivenessProbeLoop spawns the goroutine that periodically re-probes
344	// configured non-cloud providers. The goroutine is tied to QuotaRefreshContext
345	// (or context.Background()) so server callers can cancel it on shutdown.
346	func (s *service) startAlivenessProbeLoop() {
347		if s.providerProbe == nil {
348			return
349		}
350		endpoints := s.alivenessEndpoints()
351		if len(endpoints) == 0 {
352			return
353		}
354		ctx := s.opts.QuotaRefreshContext
355		if ctx == nil {
356			ctx = context.Background()
357		}
358		prober := s.opts.AlivenessProber
359		if prober == nil {
360			prober = tcpAlivenessProber
361		}
362		store := s.providerProbe
363		interval := s.healthProbeInterval()
364		persistPath := s.opts.PersistRouteHealth
365		go runAlivenessProbeLoop(ctx, endpoints, store, prober, interval, nil, nil, persistPath)
366	}
367	
368	// runAlivenessProbeLoop periodically re-probes each endpoint whose last probe
369	// is older than interval. now and sleep are seams for deterministic tests;
370	// pass nil for production defaults.
371	func runAlivenessProbeLoop(
372		ctx context.Context,
373		endpoints []alivenessEndpoint,
374		store *routehealth.ProbeStore,
375		prober ProviderAlivenessProber,
376		interval time.Duration,
377		now func() time.Time,
378		sleep func(ctx context.Context, d time.Duration) bool,
379		persistPath string,
380	) {
381		if now == nil {
382			now = time.Now
383		}
384		if sleep == nil {
385			sleep = alivenessLoopSleep
386		}
387		if interval <= 0 {
388			interval = defaultHealthProbeInterval
389		}
390		for {
391			t := now().UTC()
392			for _, ep := range endpoints {
393				if ctx.Err() != nil {
394					return
395				}
396				if !store.ProbeNeeded(ep.provider, ep.endpoint, t, interval) {
397					continue
398				}
399				probeCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
400				success := prober(probeCtx, ep.provider, ep.baseURL)
401				cancel()
402				store.RecordProbe(ep.provider, ep.endpoint, success, t)
403			}
404			if persistPath != "" {
405				_ = store.Save(persistPath)
406			}
407			if !sleep(ctx, interval) {
408				return
409			}
410		}
411	}
412	
413	func alivenessLoopSleep(ctx context.Context, d time.Duration) bool {
414		if d <= 0 {
415			return ctx.Err() == nil
416		}
417		timer := time.NewTimer(d)
418		defer timer.Stop()
419		select {
420		case <-ctx.Done():
421			return false
422		case <-timer.C:
423			return true
424		}
425	}
