427	// tcpAlivenessProber tests endpoint reachability via a TCP connect probe.
428	func tcpAlivenessProber(ctx context.Context, _, baseURL string) bool {
429		addr := extractHostPort(baseURL)
430		if addr == "" {
431			return false
432		}
433		d := net.Dialer{}
434		conn, err := d.DialContext(ctx, "tcp", addr)
435		if err != nil {
436			return false
437		}
438		_ = conn.Close()
439		return true
440	}
