442	// extractHostPort extracts host:port from a base URL, adding the scheme's
443	// default port when none is specified.
444	func extractHostPort(baseURL string) string {
445		baseURL = strings.TrimSpace(baseURL)
446		if baseURL == "" {
447			return ""
448		}
449		if !strings.Contains(baseURL, "://") {
450			baseURL = "http://" + baseURL
451		}
452		u, err := url.Parse(baseURL)
453		if err != nil {
454			return ""
455		}
456		host := u.Host
457		if host == "" {
458			return ""
459		}
460		if !strings.Contains(host, ":") {
461			switch u.Scheme {
462			case "https":
463				host += ":443"
464			default:
465				host += ":80"
466			}
467		}
468		return host
469	}
