3	import (
4		"os"
5		"sync"
6		"time"
7	)
8	
9	// ProbeRecord records the most recent aliveness probe result for a provider endpoint.
10	type ProbeRecord struct {
11		Provider         string    `json:"provider"`
12		Endpoint         string    `json:"endpoint,omitempty"`
13		LastProbeAt      time.Time `json:"last_probe_at"`
14		LastProbeSuccess bool      `json:"last_probe_success"`
15	}
16	
17	type probeKey struct {
18		Provider string
19		Endpoint string
20	}
21	
22	// ProbeStore records per-provider aliveness probe results. It is safe for concurrent use.
23	type ProbeStore struct {
24		mu      sync.RWMutex
25		records map[probeKey]ProbeRecord
26	}
27	
28	// NewProbeStore returns an empty probe store.
29	func NewProbeStore() *ProbeStore {
30		return &ProbeStore{records: make(map[probeKey]ProbeRecord)}
31	}
32	
33	// RecordProbe records an aliveness probe result for a provider/endpoint pair.
34	// Empty endpoint matches the provider's primary endpoint.
35	func (ps *ProbeStore) RecordProbe(provider, endpoint string, success bool, probeAt time.Time) {
36		if provider == "" {
37			return
38		}
39		if probeAt.IsZero() {
40			probeAt = time.Now()
41		}
42		probeAt = probeAt.UTC()
43		key := probeKey{Provider: provider, Endpoint: endpoint}
44		ps.mu.Lock()
45		defer ps.mu.Unlock()
46		ps.records[key] = ProbeRecord{
47			Provider:         provider,
48			Endpoint:         endpoint,
49			LastProbeAt:      probeAt,
50			LastProbeSuccess: success,
51		}
52	}
53	
54	// LastProbe returns the most recent probe record for a provider/endpoint pair.
55	func (ps *ProbeStore) LastProbe(provider, endpoint string) (ProbeRecord, bool) {
56		if ps == nil {
57			return ProbeRecord{}, false
58		}
59		key := probeKey{Provider: provider, Endpoint: endpoint}
60		ps.mu.RLock()
61		defer ps.mu.RUnlock()
62		r, ok := ps.records[key]
63		return r, ok
64	}
65	
66	// ProbeNeeded reports whether a provider/endpoint needs a new probe because its
67	// last probe is older than interval or has never been probed.
68	func (ps *ProbeStore) ProbeNeeded(provider, endpoint string, now time.Time, interval time.Duration) bool {
69		if ps == nil {
70			return false
71		}
72		r, ok := ps.LastProbe(provider, endpoint)
73		if !ok {
74			return true
75		}
76		return now.Sub(r.LastProbeAt) >= interval
77	}
78	
79	// UnreachableProviders returns a map of provider name → probe time for providers
80	// whose most recent probe failed within ttl of now. Used to populate
81	// routing.Inputs.ProbeUnreachable.
82	func (ps *ProbeStore) UnreachableProviders(now time.Time, ttl time.Duration) map[string]time.Time {
83		if ps == nil {
84			return nil
85		}
86		if now.IsZero() {
87			now = time.Now()
88		}
89		now = now.UTC()
90		ps.mu.RLock()
91		defer ps.mu.RUnlock()
92		var out map[string]time.Time
93		for _, r := range ps.records {
94			if r.LastProbeSuccess {
95				continue
96			}
97			if ttl > 0 && now.Sub(r.LastProbeAt) > ttl {
98				continue
99			}
100			if out == nil {
101				out = make(map[string]time.Time)
102			}
103			existing, ok := out[r.Provider]
104			if !ok || r.LastProbeAt.After(existing) {
105				out[r.Provider] = r.LastProbeAt
106			}
107		}
108		return out
109	}
110	
111	// Save persists probe records to a JSON file at path.
112	func (ps *ProbeStore) Save(path string) error {
113		return SavePersistedState(path, nil, ps)
114	}
115	
116	// Load reads probe records from a JSON file at path. Non-existent files are silently ignored.
117	func (ps *ProbeStore) Load(path string) error {
118		if ps == nil || path == "" {
119			return nil
120		}
121		if err := LoadPersistedState(path, 0, nil, ps); err != nil {
122			if os.IsNotExist(err) {
123				return nil
124			}
125			return err
126		}
127		return nil
128	}
