36	func (s *service) resolveConfiguredNativeProvider(req ServiceExecuteRequest) nativeProviderResolution {
37		sc := s.opts.ServiceConfig
38		if sc == nil {
39			return nativeProviderResolution{}
40		}
41		name, entry, ok := selectConfiguredNativeProvider(sc, req)
42		if !ok {
43			return nativeProviderResolution{}
44		}
45		if req.Model != "" {
46			entry.Model = req.Model
47		}
48		provider := s.buildNativeProvider(name, entry)
49		if provider == nil {
50			return nativeProviderResolution{Name: name, Entry: entry}
51		}
52		return nativeProviderResolution{Provider: provider, Name: name, Entry: entry}
53	}
