55	func selectConfiguredNativeProvider(sc ServiceConfig, req ServiceExecuteRequest) (string, ServiceProviderEntry, bool) {
56		if req.Provider != "" {
57			if entry, ok := sc.Provider(req.Provider); ok {
58				return req.Provider, entry, true
59			}
60			if name, entry, ok := selectConfiguredEndpointProvider(sc, req.Provider); ok {
61				return name, entry, true
62			}
63		}
64	
65		wantedType := requestedNativeProviderType(req)
66		if wantedType != "" {
67			if name := sc.DefaultProviderName(); name != "" {
68				if entry, ok := sc.Provider(name); ok && normalizeServiceProviderType(entry.Type) == wantedType {
69					return name, entry, true
70				}
71			}
72			for _, name := range sc.ProviderNames() {
73				entry, ok := sc.Provider(name)
74				if ok && normalizeServiceProviderType(entry.Type) == wantedType {
75					return name, entry, true
76				}
77			}
78		}
79	
80		if req.Provider == "" && wantedType == "" {
81			name := sc.DefaultProviderName()
82			if name == "" {
83				return "", ServiceProviderEntry{}, false
84			}
85			entry, ok := sc.Provider(name)
86			return name, entry, ok
87		}
88	
89		return "", ServiceProviderEntry{}, false
