// isReachabilityErr reports whether err carries the openai.ErrEndpointUnreachable
// sentinel. Probe implementations wrap transport/5xx failures as
// *openai.ReachabilityError; this cache uses errors.Is to detect them.
func isReachabilityErr(err error) bool {
	if err == nil {
		return false
	}
	return errors.Is(err, openai.ErrEndpointUnreachable)
}

// RecordDispatchError records a chat-completions dispatch failure observed
// outside the discovery probe path. When err is classified as a network or
// 5xx server failure (using the same predicates as probeOpenAIModels) — or
// already wrapped as *openai.ReachabilityError — the cache entry for key is
// marked unreachable so subsequent freshness/cooldown checks reflect the
// dispatch-observed failure. Returns true when err was classified as
// reachability-equivalent and the entry was updated.
//
// This is the dispatch-feedback hook the routing layer relies on to evict
// a sticky lease pinned to a dead endpoint; probe-only signal feedback
// (the original UnreachableAt source) left dispatch-observed failures
// invisible to the next routing pass within FreshTTL.
func (c *catalogCache) RecordDispatchError(key catalogCacheKey, err error) bool {
	if c == nil || err == nil {
		return false
	}
	if !isDispatchReachabilityError(err) {
		return false
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	e, ok := c.mem[key]
	if !ok {
		e = &catalogEntry{DiscoverySupported: true}
		c.mem[key] = e
	}
	e.UnreachableAt = c.opts.Now()
	e.LastErr = err
	return true
}

// SetDeploymentClass annotates the entry for key with a deployment class so
// FreshTTL resolution can pick the appropriate window. Local-class entries
// use LocalFreshTTL; everything else uses FreshTTL. If no entry exists yet,
// one is created so the next probe inherits the class.
func (c *catalogCache) SetDeploymentClass(key catalogCacheKey, class string) {
	if c == nil {
		return
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	e, ok := c.mem[key]
	if !ok {
		e = &catalogEntry{DiscoverySupported: true}
		c.mem[key] = e
	}
	e.DeploymentClass = class
}

// isDispatchReachabilityError classifies err using the same predicates as
// probeOpenAIModels so dispatch failures end up in the same UnreachableAt
// bucket as discovery-probe failures. Returns true for transport-layer
// failures (dial/timeout/reset/TLS), 5xx server errors, and anything
// already wrapped as *openai.ReachabilityError.
func isDispatchReachabilityError(err error) bool {
	if err == nil {
		return false
	}
	if isReachabilityErr(err) {
		return true
	}
	if isNetworkFailure(err) {
		return true
	}
	if isServerError(err.Error()) {
		return true
	}
	return false
}

