func (s *service) recordRouteAttemptFromFinal(final harnesses.FinalData) {
	attempt, ok := routeAttemptFromFinal(final)
	if !ok {
		return
	}
	_ = s.RecordRouteAttempt(context.Background(), attempt)
	s.recordDispatchReachabilityFromFinal(final)
}

// recordDispatchReachabilityFromFinal feeds dispatch-observed reachability
// failures back into the catalog cache (UnreachableAt) and the proactive
// probe store (ProbeUnreachable). Probe-only feedback left in-flight
// dispatch failures invisible to the next routing pass within FreshTTL — so
// a sticky lease pinned to a dead local endpoint kept burning per-dispatch
// i/o timeouts. This hook closes that gap.
func (s *service) recordDispatchReachabilityFromFinal(final harnesses.FinalData) {
	if s == nil || final.RoutingActual == nil {
		return
	}
	status := strings.ToLower(strings.TrimSpace(final.Status))
	if status != "failed" && status != "error" {
		return
	}
	errMsg := strings.TrimSpace(final.Error)
	if errMsg == "" {
		return
	}
	wrappedErr := dispatchFinalError(errMsg)
	if !isDispatchReachabilityError(wrappedErr) {
		return
	}
	provider := strings.TrimSpace(final.RoutingActual.Provider)
	if provider == "" {
		return
	}
	providerName, endpointName, _ := splitEndpointProviderRef(provider)
	if providerName == "" {
		providerName = provider
	}
	// Catalog cache: mark the entry unreachable so freshness checks against
	// the same baseURL/auth return the dispatch error rather than the stale
	// "available" entry.
	if s.catalog != nil && s.opts.ServiceConfig != nil {
		if entry, ok := lookupProviderEntryForEndpoint(s.opts.ServiceConfig, providerName, endpointName); ok && entry.BaseURL != "" {
			key := newCatalogCacheKey(entry.BaseURL, entry.APIKey, entry.Headers)
			s.catalog.RecordDispatchError(key, wrappedErr)
		}
	}
	// Routing's ProbeUnreachable gate runs off the provider probe store.
	// Promoting the dispatch-observed failure here is what produces
	// FilterReasonEndpointUnreachable on the next routing pass.
	if s.providerProbe != nil {
		s.providerProbe.RecordProbe(providerName, endpointName, false, time.Now().UTC())
		s.persistProbeStore()
	}
}

// dispatchFinalError wraps a textual final.Error so the cache classifier can
// match transport/5xx markers (e.g. "dial tcp ... i/o timeout"). The raw
// string is wrapped in a plain error so the classifier's string-sniff
// predicates work — the call site does not have access to the original
// typed error chain by the time the final has been marshalled.
func dispatchFinalError(msg string) error {
	if msg == "" {
		return nil
	}
	return dispatchFinalErrorMessage(msg)
}

type dispatchFinalErrorMessage string

func (e dispatchFinalErrorMessage) Error() string { return string(e) }

// lookupProviderEntryForEndpoint resolves the configured provider entry that
// served the request. When endpointName is non-empty, the entry's BaseURL is
// rewritten to that endpoint's BaseURL so the cache key matches the actual
// dispatch target.
func lookupProviderEntryForEndpoint(cfg ServiceConfigSource, providerName, endpointName string) (ServiceProviderEntry, bool) {
	if cfg == nil || providerName == "" {
		return ServiceProviderEntry{}, false
	}
	source, ok := cfg.(interface {
		Provider(name string) (ServiceProviderEntry, bool)
	})
	if !ok {
		return ServiceProviderEntry{}, false
	}
	entry, ok := source.Provider(providerName)
	if !ok {
		return ServiceProviderEntry{}, false
	}
	if endpointName == "" {
		return entry, true
	}
	for _, ep := range modelDiscoveryEndpoints(entry) {
		if ep.Name == endpointName {
			entry.BaseURL = ep.BaseURL
			entry.ServerInstance = ep.ServerInstance
			entry.Endpoints = []ServiceProviderEndpoint{{Name: ep.Name, BaseURL: ep.BaseURL}}
			return entry, true
		}
	}
	return entry, true
}

// TestCatalogCacheRecordsDispatchFailureAsUnreachable verifies the dispatch-
// feedback hook: a successful probe seeds the cache as available; a
// subsequent chat-completions failure with a network/timeout error stamps
// UnreachableAt and the captured error on the same entry.
func TestCatalogCacheRecordsDispatchFailureAsUnreachable(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	// T0: successful probe — entry has FetchedAt set, UnreachableAt zero.
	r, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
		return []string{"model-a"}, nil
	})
	require.NoError(t, err)
	assert.Equal(t, []string{"model-a"}, r.IDs)

	// T1 = T0 + 1s: dispatch fails with a dial timeout.
	clock.advance(1 * time.Second)
	t1 := clock.Now()
	dispatchErr := errors.New(`openai: Post "http://host/v1/chat/completions": dial tcp 100.127.38.115:8020: i/o timeout`)
	classified := cache.RecordDispatchError(key, dispatchErr)
	require.True(t, classified, "i/o timeout dispatch error must be classified as reachability")

	// Direct cache-state inspection: UnreachableAt == T1, LastErr == dispatch err.
	cache.mu.Lock()
	entry := cache.mem[key]
	require.NotNil(t, entry)
	gotUnreachable := entry.UnreachableAt
	gotErr := entry.LastErr
	cache.mu.Unlock()

	assert.Equal(t, t1, gotUnreachable, "UnreachableAt must be stamped to the dispatch-failure time")
	require.Error(t, gotErr)
	assert.ErrorIs(t, gotErr, dispatchErr, "LastErr must carry the dispatch-observed error")
}

// TestCatalogCacheRecordsDispatchFailure_NonReachabilityIgnored verifies that
// dispatch errors that aren't transport/5xx (e.g. a 400 validation error)
// don't mark the endpoint unreachable — those are caller-fixable failures,
// not endpoint health signals.
func TestCatalogCacheRecordsDispatchFailure_NonReachabilityIgnored(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	_, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
		return []string{"model-a"}, nil
	})
	require.NoError(t, err)

	// HTTP 400 is a request-validation error, not an endpoint-health signal.
	classified := cache.RecordDispatchError(key, errors.New("HTTP 400: bad request"))
	assert.False(t, classified, "HTTP 400 must not be classified as reachability")

	cache.mu.Lock()
	entry := cache.mem[key]
	require.NotNil(t, entry)
	assert.True(t, entry.UnreachableAt.IsZero(), "non-reachability error must not stamp UnreachableAt")
	cache.mu.Unlock()
}

// TestCatalogCacheRecordsDispatchFailure_NilAndCleanErrors verifies graceful
// no-op paths.
func TestCatalogCacheRecordsDispatchFailure_NilAndCleanErrors(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	assert.False(t, cache.RecordDispatchError(key, nil), "nil error is a no-op")
}

// TestCatalogCacheNoSilentRecoveryFromUnreachable verifies that once a
// dispatch failure marks the cache unreachable, subsequent Get calls within
// UnreachableCooldown return the cached reachability error and do NOT
// re-probe — even if the entry's last successful fetch is still within
// StaleTTL.
func TestCatalogCacheNoSilentRecoveryFromUnreachable(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	// Seed with a successful probe at T0.
	var callCount atomic.Int32
	probe := func(ctx context.Context) ([]string, error) {
		callCount.Add(1)
		return []string{"model-a"}, nil
	}
	_, err := cache.Get(context.Background(), key, probe)
	require.NoError(t, err)
	require.EqualValues(t, 1, callCount.Load())

	// Dispatch fails at T0+1s — within FreshTTL (10s) AND StaleTTL (60s).
	clock.advance(1 * time.Second)
	dispatchErr := errors.New(`dial tcp 192.0.2.1:8020: i/o timeout`)
	require.True(t, cache.RecordDispatchError(key, dispatchErr))

	// T0+2s: still inside UnreachableCooldown (5s); Get must return the
	// dispatch error and skip the probe — even though FetchedAt is still
	// fresh in absolute terms, the unreachable-cooldown branch takes
	// precedence.
	clock.advance(1 * time.Second)
	result, err := cache.Get(context.Background(), key, probe)
	require.Error(t, err)
	assert.ErrorIs(t, err, dispatchErr)
	assert.True(t, result.FromCache, "served from cache during cooldown")
	assert.EqualValues(t, 1, callCount.Load(),
		"must not re-probe within UnreachableCooldown after dispatch failure")
}

// TestCatalogCacheFreshTTLLocalDeploymentClass verifies AC #5: a local-class
// catalog entry resolves to LocalFreshTTL (default 10s, configurable),
// distinct from the looser FreshTTL applied to managed-cloud entries.
func TestCatalogCacheFreshTTLLocalDeploymentClass(t *testing.T) {
	// Defaults: LocalFreshTTL ≤ 15s; verify the default constant.
	assert.LessOrEqual(t, defaultCatalogLocalFreshTTL, 15*time.Second,
		"default LocalFreshTTL must be ≤ 15s for laptop-class local providers")

	// Explicit construction: local-class entry resolves to LocalFreshTTL,
	// non-local resolves to FreshTTL.
	opts := catalogCacheOptions{
		FreshTTL:      60 * time.Second,
		LocalFreshTTL: 10 * time.Second,
	}.withDefaults()

	local := &catalogEntry{DeploymentClass: CatalogDeploymentClassLocal}
	managed := &catalogEntry{DeploymentClass: "managed_cloud_subscription"}
	empty := &catalogEntry{}

	assert.Equal(t, 10*time.Second, opts.freshTTLFor(local), "local class uses LocalFreshTTL")
	assert.Equal(t, 60*time.Second, opts.freshTTLFor(managed), "managed class uses FreshTTL")
	assert.Equal(t, 60*time.Second, opts.freshTTLFor(empty), "unset class falls back to FreshTTL")
	assert.LessOrEqual(t, opts.freshTTLFor(local), 15*time.Second,
		"local-class resolved FreshTTL must be ≤ 15s per AC #5")
}

