// TestCatalogCacheProbeFailurePathUnchanged guards AC #6: the existing
// probe-driven UnreachableAt path remains unchanged. Probe failures still
// set UnreachableAt; the next successful probe still clears it.
func TestCatalogCacheProbeFailurePathUnchanged(t *testing.T) {
	clock := newStubClock()
	cache := testCache(clock)
	key := testKey("http://host/v1")

	reachErr := &openai.ReachabilityError{
		Endpoint: "http://host/v1", Operation: "probe_models", StatusCode: 502,
		Cause: errors.New("bad gateway"),
	}
	var attempt atomic.Int32
	probe := func(ctx context.Context) ([]string, error) {
		n := attempt.Add(1)
		if n == 1 {
			return nil, reachErr
		}
		return []string{"recovered"}, nil
	}

	// First probe: fails with ReachabilityError, sets UnreachableAt.
	_, err := cache.Get(context.Background(), key, probe)
	require.Error(t, err)

	cache.mu.Lock()
	require.False(t, cache.mem[key].UnreachableAt.IsZero(), "probe-driven UnreachableAt set")
	cache.mu.Unlock()

	// Advance past cooldown; next probe succeeds and clears UnreachableAt.
	clock.advance(10 * time.Second)
	_, err = cache.Get(context.Background(), key, probe)
	require.NoError(t, err)

	cache.mu.Lock()
	assert.True(t, cache.mem[key].UnreachableAt.IsZero(),
		"successful probe must clear UnreachableAt")
	cache.mu.Unlock()
}

