// TestCatalogCacheSetDeploymentClassPlumbsThroughFreshTTL verifies the
// SetDeploymentClass setter actually flips the per-entry FreshTTL window,
// so 11s of staleness on a local-class entry is "stale" (kicks an async
// refresh) while a managed-class entry at the same age is still "fresh"
// (skips the probe).
func TestCatalogCacheSetDeploymentClassPlumbsThroughFreshTTL(t *testing.T) {
	mkCache := func() *catalogCache {
		clock := newStubClock()
		return newCatalogCache(catalogCacheOptions{
			FreshTTL:            60 * time.Second,
			LocalFreshTTL:       10 * time.Second,
			StaleTTL:            5 * time.Minute,
			UnreachableCooldown: 5 * time.Second,
			UnreachableJitter:   0,
			Now:                 clock.Now,
			RandInt63n:          func(n int64) int64 { return 0 },
		}), clock
	}

	t.Run("local class becomes stale past LocalFreshTTL", func(t *testing.T) {
		cache, clock := mkCache()
		key := testKey("http://local-host/v1")
		cache.SetDeploymentClass(key, CatalogDeploymentClassLocal)

		_, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
			return []string{"model-a"}, nil
		})
		require.NoError(t, err)

		// 11s later — past LocalFreshTTL (10s) but well within FreshTTL (60s).
		clock.advance(11 * time.Second)
		r, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
			return []string{"model-a"}, nil
		})
		require.NoError(t, err)
		assert.True(t, r.Stale, "local-class entry past LocalFreshTTL must be served stale (kicks async refresh)")
	})

	t.Run("managed class is still fresh at same age", func(t *testing.T) {
		cache, clock := mkCache()
		key := testKey("http://cloud-host/v1")
		// No deployment class set — default treats as managed.

		_, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
			return []string{"model-a"}, nil
		})
		require.NoError(t, err)

		clock.advance(11 * time.Second)
		r, err := cache.Get(context.Background(), key, func(context.Context) ([]string, error) {
			return []string{"model-a"}, nil
		})
		require.NoError(t, err)
		assert.False(t, r.Stale, "managed-class entry within FreshTTL must NOT be stale")
		assert.True(t, r.FromCache, "managed-class entry within FreshTTL is served from cache")
	})
}

