)

// TestRecordDispatchReachabilityFromFinal_FeedsCatalogAndProbeStore is the
// unit-level verification of the dispatch-feedback hook: a chat-completions
// failure with a transport-class error must (1) stamp the catalog cache
// entry's UnreachableAt and (2) record a failed probe in the routing probe
// store so the next routing pass sees it as ProbeUnreachable.
func TestRecordDispatchReachabilityFromFinal_FeedsCatalogAndProbeStore(t *testing.T) {
	cacheDir := t.TempDir()
	t.Setenv("FIZEAU_CACHE_DIR", cacheDir)
	t.Setenv("PATH", "")

	const baseURL = "http://bragi.invalid:8020/v1"
	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"bragi": {Type: "lmstudio", BaseURL: baseURL, Model: "qwen"},
		},
		names:       []string{"bragi"},
		defaultName: "bragi",
	}
	rawSvc, err := New(ServiceOptions{ServiceConfig: sc, QuotaRefreshContext: canceledRefreshContext()})
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	svc := rawSvc.(*service)

	final := harnesses.FinalData{
		Status: "failed",
		Error:  `openai: Post "http://bragi.invalid:8020/v1/chat/completions": dial tcp 100.127.38.115:8020: i/o timeout`,
		RoutingActual: &harnesses.RoutingActual{
			Harness:      "fiz",
			Provider:     "bragi",
			Model:        "qwen",
			FailureClass: "transport",
		},
	}
	svc.recordDispatchReachabilityFromFinal(final)

	// Catalog cache: entry for the configured baseURL/apiKey/headers should
	// now have UnreachableAt set.
	key := newCatalogCacheKey(baseURL, "", nil)
	svc.catalog.mu.Lock()
	entry, ok := svc.catalog.mem[key]
	svc.catalog.mu.Unlock()
	if !ok {
		t.Fatal("catalog cache entry missing after dispatch-failure feedback")
	}
	if entry.UnreachableAt.IsZero() {
		t.Fatalf("UnreachableAt not stamped after dispatch failure: entry=%#v", entry)
	}

	// Provider probe store: bragi should be marked unreachable so routing's
	// ProbeUnreachable map picks it up.
	probeRecord, ok := svc.providerProbe.LastProbe("bragi", "")
	if !ok {
		t.Fatal("provider probe store has no record for bragi after dispatch feedback")
	}
	if probeRecord.LastProbeSuccess {
		t.Fatalf("probe record success=true, want false after dispatch failure: %#v", probeRecord)
	}
}

// TestRecordDispatchReachabilityFromFinal_IgnoresNonReachabilityErrors guards
// against false-positives: a final with a validation/4xx error must NOT mark
// the endpoint unreachable.
func TestRecordDispatchReachabilityFromFinal_IgnoresNonReachabilityErrors(t *testing.T) {
	t.Setenv("PATH", "")

	const baseURL = "http://bragi.invalid:8020/v1"
	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"bragi": {Type: "lmstudio", BaseURL: baseURL, Model: "qwen"},
		},
		names:       []string{"bragi"},
		defaultName: "bragi",
	}
	rawSvc, err := New(ServiceOptions{ServiceConfig: sc, QuotaRefreshContext: canceledRefreshContext()})
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	svc := rawSvc.(*service)

	final := harnesses.FinalData{
		Status: "failed",
		Error:  "validator rejected malformed tool payload",
		RoutingActual: &harnesses.RoutingActual{
			Harness:      "fiz",
			Provider:     "bragi",
			Model:        "qwen",
			FailureClass: "unknown",
		},
	}
	svc.recordDispatchReachabilityFromFinal(final)

	if _, ok := svc.providerProbe.LastProbe("bragi", ""); ok {
		t.Fatal("provider probe store should not record validation failures as reachability failures")
	}
	key := newCatalogCacheKey(baseURL, "", nil)
	svc.catalog.mu.Lock()
	entry, ok := svc.catalog.mem[key]
	svc.catalog.mu.Unlock()
	if ok && !entry.UnreachableAt.IsZero() {
		t.Fatalf("catalog cache should not mark validation failures unreachable: %#v", entry)
	}
}

// TestRoutePicksAlternateAfterDispatchFailureFeedback is AC #3: two
// equally-scored local providers A and B start as available; a dispatch
// failure observed against A (i/o timeout) must promote A into routing's
// ProbeUnreachable map so the next ResolveRoute pass excludes it with
// FilterReasonEndpointUnreachable and picks B instead. Verifies the
// end-to-end feedback loop (catalog cache + probe store + routing engine).
func TestRoutePicksAlternateAfterDispatchFailureFeedback(t *testing.T) {
	t.Setenv("PATH", "")
	cacheDir := t.TempDir()
	t.Setenv("FIZEAU_CACHE_DIR", cacheDir)
	cache := &discoverycache.Cache{Root: cacheDir}
	capturedAt := time.Date(2026, 5, 12, 15, 0, 0, 0, time.UTC)

	const (
		urlAlpha = "http://alpha.invalid:8020/v1"
		urlBeta  = "http://beta.invalid:8020/v1"
	)
	writeSnapshotDiscoveryFixture(t, cache, testDiscoverySourceName("alpha", "alpha", urlAlpha, ""), capturedAt, []string{"qwen"})
	writeSnapshotDiscoveryFixture(t, cache, testDiscoverySourceName("beta", "beta", urlBeta, ""), capturedAt, []string{"qwen"})

	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"alpha": {Type: "lmstudio", BaseURL: urlAlpha, Model: "qwen", IncludeByDefault: true, IncludeByDefaultSet: true},
			"beta":  {Type: "lmstudio", BaseURL: urlBeta, Model: "qwen", IncludeByDefault: true, IncludeByDefaultSet: true},
		},
		names:          []string{"alpha", "beta"},
		defaultName:    "alpha",
		healthCooldown: 30 * time.Second,
	}
	rawSvc, err := New(ServiceOptions{
		ServiceConfig:       sc,
		HealthSignalTTL:     10 * time.Minute,
		QuotaRefreshContext: canceledRefreshContext(),
	})
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	svc := rawSvc.(*service)

	// First dispatch: routing engine sees both alpha and beta as eligible.
	first, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
	if err != nil {
		t.Fatalf("ResolveRoute first: %v", err)
	}
	if first.Provider != "alpha" {
		t.Fatalf("first decision Provider = %q, want alpha (default)", first.Provider)
	}

	// Simulate the alpha dispatch failing with a transport-class i/o timeout.
	// This is what the chat-completions provider would return after a 5s dial
	// timeout against a dead local endpoint.
	final := harnesses.FinalData{
		Status: "failed",
		Error:  `openai: Post "http://alpha.invalid:8020/v1/chat/completions": dial tcp 198.51.100.20:8020: i/o timeout`,
		RoutingActual: &harnesses.RoutingActual{
			Harness:      "fiz",
			Provider:     "alpha",
			Model:        "qwen",
			FailureClass: "transport",
		},
	}
	svc.recordDispatchReachabilityFromFinal(final)

	// Next routing pass: alpha must be hard-gated with the
	// endpoint_unreachable filter reason; beta must be selected.
	second, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
	if err != nil {
		t.Fatalf("ResolveRoute second: %v", err)
	}
	if second.Provider != "beta" {
		t.Fatalf("second decision Provider = %q, want beta (alternate after alpha dispatch failure)", second.Provider)
	}
	var alphaCand *RouteCandidate
	for i := range second.Candidates {
		if second.Candidates[i].Provider == "alpha" {
			alphaCand = &second.Candidates[i]
			break
		}
	}
	if alphaCand == nil {
		t.Fatal("alpha candidate row missing from second routing decision")
	}
	if alphaCand.Eligible {
		t.Errorf("alpha eligible after dispatch failure feedback; want eligible=false")
	}
	if alphaCand.FilterReason != string(routing.FilterReasonEndpointUnreachable) {
		t.Errorf("alpha.FilterReason = %q, want %q", alphaCand.FilterReason, routing.FilterReasonEndpointUnreachable)
	}
}

// TestRecordDispatchReachabilityFromFinal_SuccessIsNoOp guards the success
// path: a successful final must NOT trip the dispatch-feedback hook.
func TestRecordDispatchReachabilityFromFinal_SuccessIsNoOp(t *testing.T) {
	t.Setenv("PATH", "")

	sc := &fakeServiceConfig{
		providers: map[string]ServiceProviderEntry{
			"bragi": {Type: "lmstudio", BaseURL: "http://bragi.invalid:8020/v1", Model: "qwen"},
		},
		names:       []string{"bragi"},
		defaultName: "bragi",
	}
	rawSvc, err := New(ServiceOptions{ServiceConfig: sc, QuotaRefreshContext: canceledRefreshContext()})
	if err != nil {
		t.Fatalf("New: %v", err)
	}
	svc := rawSvc.(*service)

	svc.recordDispatchReachabilityFromFinal(harnesses.FinalData{
		Status: "success",
		Error:  "",
		RoutingActual: &harnesses.RoutingActual{
			Harness:  "fiz",
			Provider: "bragi",
			Model:    "qwen",
		},
	})

	if _, ok := svc.providerProbe.LastProbe("bragi", ""); ok {
		t.Fatal("success final should not feed the provider probe store")
	}
}

